.siga-navbar {
  width: 100%;
  background: var(--siga-brand-red-mid);
  display: flex;
  justify-content: space-between;
  align-items: center;
  font-family: var(--siga-font-family);
  height: 55px;
  box-sizing: border-box;
  position: relative;
}

ul {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  height: 100%;
}

.nav-left,
.nav-right {
  display: flex;
  height: 100%;
}

.nav-item {
  height: 100%;
  display: flex;
  align-items: center;
  cursor: pointer;
  transition: var(--siga-transition-base);
  border-right: 1px solid rgba(255, 255, 255, 0.1);

  a {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    padding: 0 20px;
    height: 100%;
    color: var(--siga-text-white);
    text-decoration: none;
    transition: var(--siga-transition-base);

    i {
      font-size: 18px;
      margin-bottom: 6px;
    }

    span {
      font-size: var(--siga-font-size-xs);
      font-weight: var(--siga-font-weight-bold);
      white-space: nowrap;
      text-transform: none;
    }
  }

  /* Estado ativo com vermelho bordô do DS */
  &.active {
    background: var(--siga-brand-red-active-dark);
    box-shadow: inset 0 2px 0 rgba(0, 0, 0, 0.1);
  }

  /* Efeito de hover: preenchimento branco com texto na cor da marca */
  &:hover:not(.active) {
    background: var(--siga-text-white);

    a {
      color: var(--siga-brand-red-mid);
    }
  }
}

.nav-left .nav-item:first-child {
  border-left: none;
}

.nav-right .nav-item {
  border-right: none;
  border-left: 1px solid rgba(255, 255, 255, 0.1);
}

.right-item a i {
  font-size: 16px;
  margin-bottom: 8px;
}

